import type React from 'react';
export type HorizontalAlign = 'left' | 'center' | 'right';
export type VerticalAlign = 'top' | 'center' | 'bottom';
export interface TableProps extends React.TableHTMLAttributes<HTMLTableElement> {
    dense?: boolean;
    /**
     * @deprecated
     */
    alignRight?: boolean;
    hover?: boolean;
    horizontalAlign?: HorizontalAlign;
    verticalAlign?: VerticalAlign;
    /**
      Числовые столбцы выравниваются по правому краю
    **/
    numeric?: boolean;
    /**
      Моноширина для числовых столбцов
    **/
    monospaceNumeric?: boolean;
    /**
     * Древовидная структура таблицы
     */
    expandable?: boolean;
    /**
     * Управление прокруткой таблицы scroll.
     * x — горизонтальная прокрутка и ширина области прокрутки.
     *    Поддерживает number (px), строку (например, '100%', 'max-content') или true.
     * y — вертикальная прокрутка и высота области прокрутки.
     *    Поддерживает number (px) или строку (например, '240px', '50vh').
     */
    scroll?: {
        x?: number | string | true;
        y?: number | string;
    };
}
